final:
module RefModule(
    input               clk,
    input               rst,
    input               enable,

    output reg [7:0]    count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge dbg_halt) begin
    if (rst)
        count <= 8'b00000000;
    else if (enable)
        count <= count + 1;
end

endmodule
